const DestructiveConfirm = function Render() {
  const [loading, setLoading] = useState(false);
  const [confirmed, setConfirmed] = useState(false);

  if (confirmed) {
    return (
      <div className="flex flex-col items-center gap-3">
        <p className="text-sm text-muted-foreground">Item has been deleted.</p>
        <Button variant="outline" onClick={() => setConfirmed(false)}>Reset</Button>
      </div>
    );
  }

  return (
    <Dialog defaultOpen>
      <DialogTrigger render={<Button variant="destructive">Delete Item</Button>} />
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Confirm Deletion</DialogTitle>
          <DialogDescription>
            This action cannot be undone. This will permanently delete the selected item
            and remove all associated data.
          </DialogDescription>
        </DialogHeader>
        <div className="rounded-lg border border-destructive/20 bg-destructive/5 p-3 text-sm text-destructive">
          <p className="font-medium">Warning</p>
          <p className="mt-1 text-destructive/80">
            Deleted data cannot be recovered. Make sure you have a backup if needed.
          </p>
        </div>
        <DialogFooter showCloseButton>
          <Button variant="outline" disabled={loading}>Cancel</Button>
          <Button
            variant="destructive"
            disabled={loading}
            onClick={() => {
              setLoading(true);
              setTimeout(() => {
                setLoading(false);
                setConfirmed(true);
              }, 1500);
            }}
          >
            {loading ? "Deleting..." : "Delete"}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

